MERGE INTO CONSULTAS FIN USING (SELECT '800610F04_CDT_MOVIMIENTOS_DE_INVENTARIO' INFORME ,TO_CLOB(q'[ SELECT   CUENTA AS "Codigo_Contable",
        PLAN_CONTABLE.NOMBRE AS "Denominacion",
        SUMADESALDOANTERIOR AS "Saldo_Anterior",
        SUMADEENTRADAS AS "Entradas",
        SUMADESALIDAS AS "Salidas",
        BAJAS AS "Bajas",
        SUMADEAJUSTESCREDITO AS "Ajustes",
        (SUMADESALDOANTERIOR + SUMADEENTRADAS - SUMADESALIDAS + SUMADEAJUSTESCREDITO - BAJAS) AS "Saldo_Almacen",
         (CASE WHEN 0 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO0 ELSE 0 END
              + CASE WHEN 1 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO1 ELSE 0 END
              + CASE WHEN 2 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO2 ELSE 0 END
              + CASE WHEN 3 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO3 ELSE 0 END
              + CASE WHEN 4 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO4 ELSE 0 END
              + CASE WHEN 5 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO5 ELSE 0 END
              + CASE WHEN 6 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO6 ELSE 0 END
              + CASE WHEN 7 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO7 ELSE 0 END
              + CASE WHEN 8 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO8 ELSE 0 END
              + CASE WHEN 9 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO9 ELSE 0 END
              + CASE WHEN 10 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO10 ELSE 0 END
              + CASE WHEN 11 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO11 ELSE 0 END
              + CASE WHEN 12 = s$mesFinal$s THEN PLAN_CONTABLE.SALDO12 ELSE 0 END
            )  AS "Saldo_Final_Contabilidad"
 FROM PLAN_CONTABLE INNER JOIN (
      SELECT V_BASE_CUENTAALMACEN.COMPANIA,V_BASE_CUENTAALMACEN.CUENTA,
           SUM(CASE WHEN (V_BASE_CUENTAALMACEN.FECHA < TO_DATE('01/'||s$mesInicial$s||'/'||s$ano$s || '00:00:00','DD/MM/YYYY HH24:mi:ss'))
                THEN NVL(V_BASE_CUENTAALMACEN.VALOR_ENTRADAS,0)- NVL(V_BASE_CUENTAALMACEN.VALOR_SALIDAS,0)
                        +NVL(V_BASE_CUENTAALMACEN.AJUSTESDEBITO,0)  + NVL(V_BASE_CUENTAALMACEN.AJUSTESCREDITO,0) ELSE 0 END ) AS SUMADESALDOANTERIOR,
           SUM(CASE WHEN (V_BASE_CUENTAALMACEN.FECHA >= TO_DATE('01/'||s$mesInicial$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss') AND V_BASE_CUENTAALMACEN.FECHA <= LAST_DAY(TO_DATE('01/'||s$mesFinal$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss')))
 AND (CLASE_BODEGA_DESTINO NOT IN (60))
                     THEN NVL(V_BASE_CUENTAALMACEN.VALOR_ENTRADAS,0) ELSE 0 END ) AS SUMADEENTRADAS,
           SUM(CASE WHEN (V_BASE_CUENTAALMACEN.FECHA >= TO_DATE('01/'||s$mesInicial$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss') AND V_BASE_CUENTAALMACEN.FECHA <= LAST_DAY(TO_DATE('01/'||s$mesFinal$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss')))
 AND (CLASE_BODEGA_DESTINO NOT IN (60))
                    THEN NVL(V_BASE_CUENTAALMACEN.VALOR_SALIDAS,0) ELSE 0 END )  AS SUMADESALIDAS,
           SUM(CASE WHEN (V_BASE_CUENTAALMACEN.FECHA >= TO_DATE('01/'||s$mesInicial$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss') AND V_BASE_CUENTAALMACEN.FECHA <= LAST_DAY(TO_DATE('01/'||s$mesFinal$s||'/'||]') || TO_CLOB(q'[s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss')))
                      THEN NVL(V_BASE_CUENTAALMACEN.AJUSTESDEBITO,0) ELSE 0 END ) +
           SUM(CASE WHEN (V_BASE_CUENTAALMACEN.FECHA >= TO_DATE('01/'||s$mesInicial$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss') AND V_BASE_CUENTAALMACEN.FECHA <= LAST_DAY(TO_DATE('01/'||s$mesFinal$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss')))
                    THEN NVL(V_BASE_CUENTAALMACEN.AJUSTESCREDITO,0) ELSE 0 END )  AS SUMADEAJUSTESCREDITO,
            SUM(CASE WHEN CLASE_BODEGA_DESTINO IN (60) THEN CASE WHEN (V_BASE_CUENTAALMACEN.FECHA >= TO_DATE('01/'||s$mesInicial$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss') AND V_BASE_CUENTAALMACEN.FECHA <= LAST_DAY(TO_DATE('01/'||s$mesFinal$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss')))
                     THEN NVL(V_BASE_CUENTAALMACEN.VALOR_SALIDAS,0) ELSE 0 END ELSE 0 END) AS BAJAS,
           SUM(NVL(V_BASE_CUENTAALMACEN.VALOR_ENTRADAS,0)-NVL(V_BASE_CUENTAALMACEN.VALOR_SALIDAS,0)+
               NVL(V_BASE_CUENTAALMACEN.AJUSTESDEBITO,0) +NVL(V_BASE_CUENTAALMACEN.AJUSTESCREDITO,0))  AS SUMADESALDOFINAL
    FROM V_BASE_CUENTAALMACEN
      WHERE V_BASE_CUENTAALMACEN.COMPANIA= s$compania$s
      AND V_BASE_CUENTAALMACEN.FECHA BETWEEN s$fechaCorte$s AND LAST_DAY(TO_DATE('01/'||s$mesFinal$s||'/'||s$ano$s|| '00:00:00','DD/MM/YYYY HH24:mi:ss'))
      AND V_BASE_CUENTAALMACEN.IND_REG NOT IN (0)
    GROUP BY    V_BASE_CUENTAALMACEN.COMPANIA,
              V_BASE_CUENTAALMACEN.CUENTA) VISTA_CUENTAALMACEN
       ON VISTA_CUENTAALMACEN.COMPANIA =PLAN_CONTABLE.COMPANIA
      AND  VISTA_CUENTAALMACEN.CUENTA = PLAN_CONTABLE.CODIGO
      AND s$ano$s =PLAN_CONTABLE.ANO
WHERE  ABS(SUMADESALDOANTERIOR) + ABS(SUMADEENTRADAS) +ABS( SUMADESALIDAS) + ABS(SUMADEAJUSTESCREDITO) <> 0
ORDER BY  CUENTA]') CONSULTA, 99 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);